UPDATE medical_report
register_id = #{registerId}, patient_id = #{patientId}, request_type = #{requestType}, request_id = #{requestId}, report_title = #{reportTitle}, report_text = #{reportText}, report_file_url = #{reportFileUrl}, report_time = #{reportTime}, is_viewed = #{isViewed}, viewed_time = #{viewedTime}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT mr.id AS id, mr.report_title AS reportTitle, mr.request_type AS requestType, CASE mr.request_type WHEN 'INSPECTION' THEN '检验报告' WHEN 'CHECK' THEN '检查报告' WHEN 'IMAGE' THEN '影像报告' ELSE '其他' END AS requestTypeName, d.dept_name AS deptName, p.real_name AS patientName, mr.report_time AS reportTime, mr.is_viewed AS isViewed FROM medical_report mr LEFT JOIN register r ON mr.register_id = r.id LEFT JOIN department d ON r.deptment_id = d.id LEFT JOIN patient p ON mr.patient_id = p.id WHERE mr.patient_id = #{patientId}
AND mr.request_type = #{requestType}
ORDER BY mr.report_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM medical_report
WHERE patient_id = #{patientId}

    AND request_type = #{requestType}
